753	/// Read and push a Lua number from `file`. Return `true` on success.
754	/// C: `read_number(L, f)`.
755	fn read_number(
756	    state: &mut LuaState,
757	    file: &mut dyn LuaFileHandle,
758	) -> Result<bool, LuaError> {
759	    // C: do { rn.c = l_getc(rn.f); } while (isspace(rn.c)); /* skip spaces */
760	    let first = loop {
761	        let b = file.read_byte();
762	        if b == EOF_SENTINEL || !(b as u8).is_ascii_whitespace() {
763	            break b;
764	        }
765	    };
766	
767	    let mut rn = ReadNumState::new(first);
768	
769	    // C: test2(&rn, "-+")
770	    rn.try2(file, [b'-', b'+']);
771	
772	    // C: if (test2(&rn, "00")) { if (test2(&rn, "xX")) hex = 1; else count = 1; }
773	    let mut count: usize = 0;
774	    let hex = if rn.try2(file, [b'0', b'0']) {
775	        if rn.try2(file, [b'x', b'X']) {
776	            true
777	        } else {
778	            count = 1;
779	            false
780	        }
781	    } else {
782	        false
783	    };
784	
785	    // C: count += readdigits(&rn, hex);
786	    count += rn.read_digits(file, hex);
787	
788	    // C: decp[0] = lua_getlocaledecpoint(); decp[1] = '.';
789	    // TODO(port): locale decimal-point character; defaulting to '.'
790	    let dec_point = b'.';
791	    if rn.try2(file, [dec_point, b'.']) {
792	        count += rn.read_digits(file, hex);
793	    }
794	
795	    // C: if (count > 0 && test2(&rn, hex ? "pP" : "eE")) { ... exponent ... }
796	    if count > 0 {
797	        let exp_chars = if hex { [b'p', b'P'] } else { [b'e', b'E'] };
798	        if rn.try2(file, exp_chars) {
799	            rn.try2(file, [b'-', b'+']);
800	            rn.read_digits(file, false);
801	        }
802	    }
803	
804	    // C: ungetc(rn.c, rn.f);
805	    file.unread_byte(rn.current);
806	
807	    // C: if (lua_stringtonumber(L, rn.buff)) return 1; else { lua_pushnil(L); return 0; }
