    state: &mut LuaState,
    file: &mut dyn LuaFileHandle,
    chop: bool,
) -> Result<bool, LuaError> {
    let mut buf: Vec<u8> = Vec::new();
    let mut c: i32 = EOF_SENTINEL;

    // C: do { char *buff = luaL_prepbuffer(&b); int i = 0;
    //          while (i < LUAL_BUFFERSIZE && (c = l_getc(f)) != EOF && c != '\n')
    //            buff[i++] = c;
    //          luaL_addsize(&b, i);
